mapper.select:
SELECT COUNT(*)
FROM SSNT_EVNT E
WHERE E.SSNT_YR = #{ssntYr}
AND E.TM_ID = #{tmId}
AND E.EVNT_TYPE_CD = #{evntTypeCd}

mapper.update:
UPDATE SSNT_EVNT
SET RD_YN = '1'
WHERE EVNT_ID = #{evntId}

UPDATE SSNT
SET CUR_DT = DATE_ADD(CUR_DT, INTERVAL 1 DAY)
WHERE SSNT_YR = #{ssntYr}

UPDATE SSNT
SET SSNT_STTS_CD = #{sttsCd}
WHERE SSNT_YR = #{ssntYr}

mapper.select:
SELECT COUNT(*)
FROM GAME
WHERE SSNT_YR    = #{ssntYr}
  AND GAME_DT    = #{curDt}
  AND GAME_STTS_CD NOT IN ('03', '05', '06')

SELECT CFG_VAL
FROM GAME_CFG
WHERE CFG_KEY = #{cfgKey}
